const mapaMotoqueiros = {
  1: "KENNEDY",
  2: "FRANCISCO",
  3: "JEOVA",
  4: "RICARDO",
  5: "SANDRO",
  6: "OUTROS",
  7: "CKELY",
  8: "PRISCILA"
};

return $input.all().map(item => {
  // 🔹 extrai apenas a data (remove hora)
  const dataOriginal = item.json.DATA || "";
  const data = String(dataOriginal).split(' ')[0];

  // 🔹 traduz motoqueiro
  const codigo = item.json.MOTOQUEIROS;
  const nomeMotoqueiro = mapaMotoqueiros[codigo] || "NÃO IDENTIFICADO";

  return {
    json: {
      ...item.json,
      DATA: data, // substitui pela data sem hora
      MOTOQUEIROS: nomeMotoqueiro
    }
  };
});

const itens = $input.all();

const normalizar = (txt) =>
  String(txt || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/\s+/g, " ")
    .trim();

// Separa a tabela de conversão APP -> PLANILHA
const relMot = itens.filter(item =>
  item.json.APP !== undefined &&
  item.json.PLANILHA !== undefined
);

// Separa os dados principais
const dados = itens.filter(item =>
  !(item.json.APP !== undefined && item.json.PLANILHA !== undefined)
);

// Monta mapa de substituição
const mapa = {};

for (const item of relMot) {
  const app = normalizar(item.json.APP);
  const planilha = item.json.PLANILHA;

  if (app && planilha) {
    mapa[app] = planilha;
  }
}

// Troca os NOMES DAS CHAVES dos dados principais
return dados.map(item => {
  const novoJson = {};

  for (const [chave, valor] of Object.entries(item.json)) {
    const chaveNormalizada = normalizar(chave);

    const novaChave = mapa[chaveNormalizada] || chave;

    novoJson[novaChave] = valor;
  }

  return {
    json: novoJson
  };
});

const input1 = $input.all(0); // dados principais já convertidos
