const getData = (data) => String(data || "").split(" ")[0];
const getMotoqueiro = (m) => String(m || "").trim();

const toNumber = (v) => {
  if (v === "" || v === null || v === undefined) return "";
  const n = Number(String(v).replace(",", "."));
