  const chaveGrupo = `${data}|${moto}`;

  const valorDinheiro = toNumber(json["(-)ENTREGUE DINHEIRO DO POSTO"]);
  const valor = valorDinheiro === "" ? 0 : Math.abs(valorDinheiro);

  somaPorGrupo[chaveGrupo] = (somaPorGrupo[chaveGrupo] || 0) + valor;
